/**
 * Headroom Proxy Provider Extension
 *
 * Registers providers that route LLM traffic through the local Headroom
 * compression proxy (http://localhost:8787/v1) for 60-95% token reduction.
 *
 * Detects your existing provider config (OpenRouter, Google, Ollama) and
 * registers matching Headroom-wrapped providers so you keep API compatibility.
 *
 * Usage:
 *   /reload                    → loads this extension
 *   /model Headroom Proxy     → uses OpenRouter/Ollama through Headroom
 *   /model Headroom Google    → uses Google Gemini through Headroom
 */

import type { ExtensionAPI, ModelDefinition } from "@earendil-works/pi-coding-agent";
import { readFile } from "node:fs/promises";
import { homedir } from "node:os";
import { join } from "node:path";

const HEADROOM_BASE = "http://localhost:8787/v1";

// ──────────────────────────────────────────────────────────────
// OpenRouter models — your default provider
// ──────────────────────────────────────────────────────────────
const OPENROUTER_MODELS: ModelDefinition[] = [
	{
		id: "deepseek/deepseek-v4-flash",
		name: "DeepSeek V4 Flash (via Headroom)",
		reasoning: false,
		input: ["text"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 128000,
		maxTokens: 16384,
	},
	{
		id: "deepseek/deepseek-chat",
		name: "DeepSeek Chat (via Headroom)",
		reasoning: false,
		input: ["text"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 128000,
		maxTokens: 8192,
	},
	{
		id: "mistralai/mistral-small-3.1-24b",
		name: "Mistral Small 24B (via Headroom)",
		reasoning: false,
		input: ["text"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 32000,
		maxTokens: 4096,
	},
	{
		id: "google/gemini-2.0-flash-exp",
		name: "Gemini 2.0 Flash (via Headroom)",
		reasoning: false,
		input: ["text", "image"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 1048576,
		maxTokens: 8192,
	},
	{
		id: "meta-llama/llama-3.3-70b-instruct",
		name: "Llama 3.3 70B (via Headroom)",
		reasoning: false,
		input: ["text"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 128000,
		maxTokens: 4096,
	},
	{
		id: "qwen/qwq-32b",
		name: "QwQ 32B (via Headroom)",
		reasoning: true,
		input: ["text"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 32000,
		maxTokens: 4096,
	},
];

// ──────────────────────────────────────────────────────────────
// Google Gemini models
// ──────────────────────────────────────────────────────────────
const GOOGLE_MODELS: ModelDefinition[] = [
	{
		id: "gemini-2.5-pro-exp-03-25",
		name: "Gemini 2.5 Pro (via Headroom)",
		reasoning: true,
		input: ["text", "image"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 1048576,
		maxTokens: 64000,
	},
	{
		id: "gemini-2.0-flash",
		name: "Gemini 2.0 Flash (via Headroom)",
		reasoning: false,
		input: ["text", "image", "audio"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 1048576,
		maxTokens: 8192,
	},
	{
		id: "gemini-2.0-flash-lite-preview-02-05",
		name: "Gemini 2.0 Flash Lite (via Headroom)",
		reasoning: false,
		input: ["text", "image"],
		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: 1048576,
		maxTokens: 8192,
	},
];

// ──────────────────────────────────────────────────────────────
// Helpers
// ──────────────────────────────────────────────────────────────

async function readModelsJson(): Promise<Record<string, any> | null> {
	try {
		const raw = await readFile(join(homedir(), ".pi/agent/models.json"), "utf-8");
		return JSON.parse(raw);
	} catch {
		return null;
	}
}

/**
 * Extract Ollama models from the user's custom models.json.
 */
function getOllamaModels(modelsJson: Record<string, any> | null): ModelDefinition[] {
	if (!modelsJson?.providers?.ollama?.models) return [];

	return (modelsJson.providers.ollama.models as any[]).map((m) => ({
		id: m.id,
		name: `${m.name} (via Headroom)`,
		reasoning: m.reasoning ?? false,
		input: m.input ?? ["text"],
		cost: m.cost ?? { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
		contextWindow: m.contextWindow ?? 16384,
		maxTokens: m.maxTokens ?? 4096,
	}));
}

// ──────────────────────────────────────────────────────────────
// Extension Entry Point
// ──────────────────────────────────────────────────────────────

export default async function (pi: ExtensionAPI) {
	const modelsJson = await readModelsJson();
	const ollamaModels = getOllamaModels(modelsJson);

	// ── Provider 1: OpenRouter/Ollama via Headroom ──────────
	pi.registerProvider("headroom-proxy", {
		baseUrl: HEADROOM_BASE,
		api: "openai-responses",
		models: [...OPENROUTER_MODELS, ...ollamaModels],
	});

	// ── Provider 2: Google Gemini via Headroom ──────────────
	pi.registerProvider("headroom-google", {
		baseUrl: HEADROOM_BASE,
		api: "google-generative-ai",
		models: GOOGLE_MODELS,
	});
}

