/**
 * Headroom Proxy Provider Extension
 *
 * Registers providers that route LLM traffic through the local Headroom
 * compression proxy (http://localhost:8787/v1) for 60-95% token reduction.
 *
 * Auto-detects your existing API keys from auth.json so Headroom receives
 * the credentials it needs to authenticate upstream.
 *
 * Usage:
 *   /reload                     → loads this extension
 *   /model Headroom Proxy      → OpenRouter/Ollama/Cerebras through Headroom
 *   /model Headroom Google     → Gemini through Headroom
 *
 * Your existing providers (openrouter, google, ollama) remain untouched.
 */

import type { ExtensionAPI, ProviderConfigInput } from "@earendil-works/pi-coding-agent";
import { readFile } from "node:fs/promises";
import { homedir } from "node:os";
import { join } from "node:path";

const HEADROOM_BASE = "http://localhost:8787/v1";
const AUTH_FILE = join(homedir(), ".pi/agent/auth.json");
const MODELS_FILE = join(homedir(), ".pi/agent/models.json");

// ──────────────────────────────────────────────────────────────
// OpenRouter models — your default provider
// ──────────────────────────────────────────────────────────────
function makeOpenRouterModels(): ProviderConfigInput["models"] {
	return [
		{
			id: "deepseek/deepseek-v4-flash",
			name: "DeepSeek V4 Flash (via Headroom)",
			reasoning: false,
			input: ["text"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 128_000,
			maxTokens: 16_384,
		},
		{
			id: "deepseek/deepseek-chat",
			name: "DeepSeek Chat (via Headroom)",
			reasoning: false,
			input: ["text"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 128_000,
			maxTokens: 8_192,
		},
		{
			id: "mistralai/mistral-small-3.1-24b",
			name: "Mistral Small 24B (via Headroom)",
			reasoning: false,
			input: ["text"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 32_000,
			maxTokens: 4_096,
		},
		{
			id: "google/gemini-2.0-flash-exp",
			name: "Gemini 2.0 Flash Exp (via Headroom)",
			reasoning: false,
			input: ["text", "image"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 1_048_576,
			maxTokens: 8_192,
		},
		{
			id: "meta-llama/llama-3.3-70b-instruct",
			name: "Llama 3.3 70B (via Headroom)",
			reasoning: false,
			input: ["text"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 128_000,
			maxTokens: 4_096,
		},
		{
			id: "qwen/qwq-32b",
			name: "QwQ 32B (via Headroom)",
			reasoning: true,
			input: ["text"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 32_000,
			maxTokens: 4_096,
		},
	];
}

// ──────────────────────────────────────────────────────────────
// Google Gemini models
// ──────────────────────────────────────────────────────────────
function makeGoogleModels(): ProviderConfigInput["models"] {
	return [
		{
			id: "gemini-2.5-pro-exp-03-25",
			name: "Gemini 2.5 Pro Exp (via Headroom)",
			reasoning: true,
			input: ["text", "image"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 1_048_576,
			maxTokens: 64_000,
		},
		{
			id: "gemini-2.0-flash",
			name: "Gemini 2.0 Flash (via Headroom)",
			reasoning: false,
			input: ["text", "image", "audio"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 1_048_576,
			maxTokens: 8_192,
		},
		{
			id: "gemini-2.0-flash-lite-preview-02-05",
			name: "Gemini 2.0 Flash Lite (via Headroom)",
			reasoning: false,
			input: ["text", "image"],
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: 1_048_576,
			maxTokens: 8_192,
		},
	];
}

// ──────────────────────────────────────────────────────────────
// Ollama models from your models.json
// ──────────────────────────────────────────────────────────────
async function loadOllamaModels(): Promise<ProviderConfigInput["models"]> {
	try {
		const raw = await readFile(MODELS_FILE, "utf-8");
		const cfg = JSON.parse(raw);
		const ollamaModels = cfg?.providers?.ollama?.models;
		if (!Array.isArray(ollamaModels) || ollamaModels.length === 0) return [];

		return (ollamaModels as any[]).map((m) => ({
			id: m.id,
			name: `${m.name ?? m.id} (via Headroom)`,
			reasoning: m.reasoning ?? false,
			input: (m.input ?? ["text"]) as ("text" | "image")[],
			cost: m.cost ?? { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
			contextWindow: m.contextWindow ?? 16_384,
			maxTokens: m.maxTokens ?? 4_096,
		}));
	} catch {
		return [];
	}
}

// ──────────────────────────────────────────────────────────────
// Read API keys from auth.json
// ──────────────────────────────────────────────────────────────
interface AuthData {
	[key: string]: { type: string; key?: string } | undefined;
}

async function readAuth(): Promise<AuthData> {
	try {
		const raw = await readFile(AUTH_FILE, "utf-8");
		return JSON.parse(raw);
	} catch {
		return {};
	}
}

// ──────────────────────────────────────────────────────────────
// Extension Entry Point (async factory)
// ──────────────────────────────────────────────────────────────

export default async function (pi: ExtensionAPI) {
	const auth = await readAuth();
	const ollamaModels = await loadOllamaModels();

	// Resolve API keys
	const openRouterKey = process.env.OPENROUTER_API_KEY ?? auth.openrouter?.key;
	const googleKey = process.env.GOOGLE_API_KEY ?? auth.google?.key;

	// ── Provider 1: OpenRouter / Ollama via Headroom ──────────
	pi.registerProvider("headroom-proxy", {
		baseUrl: HEADROOM_BASE,
		api: "openai-responses",
		authHeader: true,
		apiKey: openRouterKey ?? "$OPENROUTER_API_KEY",
		models: [...makeOpenRouterModels(), ...ollamaModels],
	});

	// ── Provider 2: Google Gemini via Headroom ────────────────
	pi.registerProvider("headroom-google", {
		baseUrl: HEADROOM_BASE,
		api: "google-generative-ai",
		authHeader: true,
		apiKey: googleKey ?? "$GOOGLE_API_KEY",
		models: makeGoogleModels(),
	});
}

/**
 * Headroom CCR (Compress-Cache-Retrieve) Tool Extension
 *
 * When Headroom aggressively compresses a payload (tool output, file read, etc.)
 * it leaves a compression marker with an ID. The LLM can call headroom_retrieve
 * to fetch the original uncompressed text from Headroom's local cache.
 *
 * This implements the "Retrieve" part of the CCR pattern, ensuring full
 * reversibility even at 60-95% compression ratios.
 *
 * Usage:
 *   /reload  → tool becomes available to the LLM in the next turn
 *
 * The LLM will see this tool listed and can call it when it needs to inspect
 * the full original content that Headroom has compressed.
 */

import { Type } from "typebox";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

const HEADROOM_RETRIEVE_URL = "http://localhost:8787/retrieve";

export default function (pi: ExtensionAPI) {
	pi.registerTool({
		name: "headroom_retrieve",
		label: "Headroom Retrieve",
		description:
			"Fetch the original, uncompressed context of a payload that Headroom has compressed. " +
			"Requires the compression ID that was embedded in the compressed output. " +
			"Call this when you suspect a compressed snippet is incomplete or you need the full original text.",
		promptSnippet: "Retrieve full original text compressed by Headroom",
		promptGuidelines: [
			"Use headroom_retrieve when Headroom has compressed a tool output or file read and you need the complete original content.",
		],
		parameters: Type.Object({
			id: Type.String({
				description: "The compression marker ID left by Headroom in the compressed payload",
			}),
		}),
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const url = `${HEADROOM_RETRIEVE_URL}?id=${encodeURIComponent(params.id)}`;
			const response = await fetch(url);

			if (!response.ok) {
				const errorText = await response.text().catch(() => "Unknown error");
				return {
					content: [
						{
							type: "text",
							text: `Headroom retrieval failed (${response.status}): ${errorText}`,
						},
					],
					isError: true,
					details: {
						statusCode: response.status,
						compressionId: params.id,
					},
				};
			}

			const originalText = await response.text();

			// Report token savings if Headroom provides them
			let tokenSavings = undefined;
			const savingsHeader = response.headers.get("x-headroom-tokens-saved");
			if (savingsHeader) {
				tokenSavings = parseInt(savingsHeader, 10);
			}

			const details: Record<string, unknown> = {
				compressionId: params.id,
				originalLength: originalText.length,
			};
			if (tokenSavings !== undefined && !isNaN(tokenSavings)) {
				details.tokensSaved = tokenSavings;
			}

			return {
				content: [{ type: "text", text: originalText }],
				details,
			};
		},
	});
}

